proof_block:
// The ensures clause has the shape `LHS ==> det_eq` — a single big
// implication, where `LHS` is the original receive_with_demarshal ensures
// applied separately to (r1, post1_netc) and (r2, post2_netc).
//
// The previous attempt asserted individual conjuncts of LHS unconditionally;
// those asserts failed because each conjunct only holds under the LHS
// hypothesis, and the proof body sees `LHS ==> det_eq` as the *goal*, not as
// a hypothesis. The fix is to do all conjunct-surfacing inside an
// `if (LHS) { ... }` block, so Verus has LHS as a ground hypothesis when
// checking the asserts. Outside the `if`, the implication is vacuously
// discharged by the !LHS branch.

if (({let (rr, net_event) = r1;
        &&& post1_netc.my_end_point() == pre_netc.my_end_point()
        &&& post1_netc.ok() == !(rr is Fail)
        &&& !(rr is Fail) ==> post1_netc.ok() && post1_netc.history() == pre_netc.history() + seq!( net_event@ )
        &&& rr is Timeout ==> net_event@ is TimeoutReceive
        &&& (rr is Packet ==> {
            &&& net_event@ is Receive
            &&& true
            &&& rr.arrow_Packet_cpacket().abstractable()
            &&& true
            &&& !(rr.arrow_Packet_cpacket()@.msg is InvalidMessage) ==> {
                &&& rr.arrow_Packet_cpacket()@ == abstractify_net_packet_to_sht_packet(net_event@.arrow_Receive_r())
                &&& rr.arrow_Packet_cpacket().msg@ == sht_demarshal_data(net_event@.arrow_Receive_r().msg)@
            }
            &&& rr.arrow_Packet_cpacket().dst@ == local_addr@
        })
    }) && ({let (rr, net_event) = r2;
        &&& post2_netc.my_end_point() == pre_netc.my_end_point()
        &&& post2_netc.ok() == !(rr is Fail)
        &&& !(rr is Fail) ==> post2_netc.ok() && post2_netc.history() == pre_netc.history() + seq!( net_event@ )
        &&& rr is Timeout ==> net_event@ is TimeoutReceive
        &&& (rr is Packet ==> {
            &&& net_event@ is Receive
            &&& true
            &&& rr.arrow_Packet_cpacket().abstractable()
            &&& true
            &&& !(rr.arrow_Packet_cpacket()@.msg is InvalidMessage) ==> {
                &&& rr.arrow_Packet_cpacket()@ == abstractify_net_packet_to_sht_packet(net_event@.arrow_Receive_r())
                &&& rr.arrow_Packet_cpacket().msg@ == sht_demarshal_data(net_event@.arrow_Receive_r().msg)@
            }
            &&& rr.arrow_Packet_cpacket().dst@ == local_addr@
        })
    }))
{
    // Run 1 conjuncts (rr = r1.0, net_event = r1.1) -- now in scope.
    assert(post1_netc.my_end_point() == pre_netc.my_end_point());
    assert(post1_netc.ok() == !(r1.0 is Fail));
    assert(!(r1.0 is Fail) ==> post1_netc.ok()
        && post1_netc.history() == pre_netc.history() + seq!( r1.1@ ));
    assert(r1.0 is Timeout ==> r1.1@ is TimeoutReceive);
    assert(r1.0 is Packet ==> r1.1@ is Receive);
    assert(r1.0 is Packet ==> r1.0.arrow_Packet_cpacket().dst@ == local_addr@);

    // Run 2 conjuncts (rr = r2.0, net_event = r2.1) -- now in scope.
    assert(post2_netc.my_end_point() == pre_netc.my_end_point());
    assert(post2_netc.ok() == !(r2.0 is Fail));
    assert(!(r2.0 is Fail) ==> post2_netc.ok()
        && post2_netc.history() == pre_netc.history() + seq!( r2.1@ ));
    assert(r2.0 is Timeout ==> r2.1@ is TimeoutReceive);
    assert(r2.0 is Packet ==> r2.1@ is Receive);
    assert(r2.0 is Packet ==> r2.0.arrow_Packet_cpacket().dst@ == local_addr@);

    // Cross-run alignments that follow directly from the two ensures blocks:
    // both posts share the pre's end-point, so they agree on my_end_point().
    assert(post1_netc.my_end_point() == post2_netc.my_end_point());

    // The post.ok()s are pinned to the r*.0 is Fail discriminators, so when
    // those discriminators agree the ok-bits agree, and consequently (when
    // neither is Fail) the history extensions also have matching shape.
    assert((r1.0 is Fail) == (r2.0 is Fail)
        ==> post1_netc.ok() == post2_netc.ok());
    assert((r1.0 is Fail) == (r2.0 is Fail) && !(r1.0 is Fail)
        ==> post1_netc.history() == pre_netc.history() + seq!( r1.1@ )
         && post2_netc.history() == pre_netc.history() + seq!( r2.1@ ));
}
